     1→import React, { useState, useEffect, useCallback } from 'react';
     2→import { Modal } from '../../components/Modal';
     3→import { RecurrencePicker } from '../../components/RecurrencePicker';
     4→import { CustomFieldEditor } from '../../components/CustomFieldEditor';
     5→import { DependencyPicker } from '../../components/DependencyPicker';
     6→import { DependentShiftConfirmation } from '../../components/DependentShiftConfirmation';
     7→import AssigneePicker from '../../components/AssigneePicker';
     8→import FileUpload from '../../components/FileUpload';
     9→import AttachmentList from '../../components/AttachmentList';
    10→import ImagePreviewModal from '../../components/ImagePreviewModal';
    11→import { NaturalLanguageDateInput } from '../../components/NaturalLanguageDateInput';
    12→import { useKanbanStore } from '../../stores/useKanbanStore';
    13→import { useTimeTrackingStore } from '../../stores/useTimeTrackingStore';
    14→import { useSettingsStore } from '../../stores/useSettingsStore';
    15→import { useTemplateStore } from '../../stores/useTemplateStore';
    16→import { calculateDependentShifts, shouldAutoShift } from '../../services/taskDependencyShift';
    17→import { formatDateForDisplay } from '../../utils/naturalLanguageDates';
    18→import { differenceInDays } from 'date-fns';
    19→import type { Task, TaskPriority, TaskStatus, EffortEstimate, CustomStatus, DependencyType, TaskDependency, TaskAttachment } from '../../types';
    20→import type { FieldDefinition } from '../../types/customFields';
    21→
    22→/**
    23→ * TaskCustomFields - Separate component to properly use hooks
    24→ * Extracted to avoid Rules of Hooks violation (hooks cannot be called inside IIFEs)
    25→ */
    26→const TaskCustomFields: React.FC<{
    27→  task: Task;
    28→  onSave: (taskId: string, updates: Partial<Task>) => void;
    29→}> = ({ task, onSave }) => {
    30→  const { customFieldDefinitions } = useSettingsStore();
    31→  const taskFields = customFieldDefinitions.tasks;
    32→
    33→  if (taskFields.length === 0) return null;
    34→
    35→  return (
    36→    <div>
    37→      <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
    38→        Custom Fields
    39→      </label>
    40→      <div className="space-y-3">
    41→        {taskFields.map((field: FieldDefinition) => {
    42→          const currentValue = task?.customFields?.[field.id];
    43→
    44→          return (
    45→            <div key={field.id}>
    46→              <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
    47→                {field.name}
    48→                {field.required && (
    49→                  <span className="text-status-error-text dark:text-status-error-text-dark ml-1">*</span>
    50→                )}
    51→              </label>
    52→              {field.description && (
    53→                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-1">
    54→                  {field.description}
    55→                </p>
    56→              )}
    57→              <CustomFieldEditor
    58→                field={field}
    59→                value={currentValue}
    60→                onChange={(value) => {
    61→                  if (!task) return;
    62→                  const updatedCustomFields = {
    63→                    ...task.customFields,
    64→                    [field.id]: value,
    65→                  };
    66→                  onSave(task.id, { customFields: updatedCustomFields });
    67→                }}
    68→              />
    69→            </div>
    70→          );
    71→        })}
    72→      </div>
    73→    </div>
    74→  );
    75→};
    76→
    77→interface CardDetailPanelProps {
    78→  task: Task | null;
    79→  isOpen: boolean;
    80→  onClose: () => void;
    81→  onSave: (taskId: string, updates: Partial<Task>) => void;
    82→  columns: Array<{ id: string; title: string; color: string }>;
    83→  initialTab?: 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments';
    84→  onCardClick?: (task: Task) => void;
    85→}
    86→
    87→/**
    88→ * Card Detail Panel
    89→ * Full-screen modal for viewing and editing task details
    90→ *
    91→ * Features:
    92→ * - Left side: Task metadata (title, description, dates, priority, tags, status)
    93→ * - Right side: Tabs (Checklist, Comments, Activity Log)
    94→ * - Inline editing (auto-save on blur)
    95→ * - Keyboard shortcuts (Esc to close, Cmd+Enter to save)
    96→ * - Tab persistence (remembers last active tab)
    97→ * - Responsive design (mobile, tablet, desktop)
    98→ */
    99→export const CardDetailPanel: React.FC<CardDetailPanelProps> = ({
   100→  task,
   101→  isOpen,
   102→  onClose,
   103→  onSave,
   104→  columns,
   105→  initialTab,
   106→  onCardClick,
   107→}) => {
   108→  // Kanban store actions
   109→  const {
   110→    tasks,
   111→    addChecklistItem,
   112→    updateChecklistItem,
   113→    deleteChecklistItem,
   114→    toggleChecklistItem,
   115→    addComment,
   116→    addSubtask,
   117→    deleteSubtask,
   118→    toggleSubtask,
   119→    addDependency,
   120→    removeDependency,
   121→    getBlocked,
   122→    updateEffort,
   123→    updateCustomStatus,
   124→    startTimer,
   125→    stopTimer: stopKanbanTimer,
   126→    updateTimeEstimate,
   127→    setTaskRecurrence,
   128→    applyDependentShifts,
   129→    addAttachment,
   130→    deleteAttachment,
   131→  } = useKanbanStore();
   132→
   133→  // Time tracking store (Phase A: Time Tracking Integration)
   134→  const {
   135→    getEntriesForCard,
   136→    getTotalTimeForCard,
   137→    startTimerForCard,
   138→    stopTimer,
   139→    activeEntry,
   140→  } = useTimeTrackingStore();
   141→
   142→  // Template store (P2: Task Templates)
   143→  const { createTemplate } = useTemplateStore();
   144→
   145→  // Tab state with persistence
   146→  const [activeTab, setActiveTab] = useState<'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments'>(() => {
   147→    if (initialTab) return initialTab;
   148→    const saved = localStorage.getItem('kanban-detail-panel-tab');
   149→    return (saved as 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments') || 'subtasks';
   150→  });
   151→
   152→  // Sync activeTab with initialTab when it changes
   153→  useEffect(() => {
   154→    if (initialTab) {
   155→      setActiveTab(initialTab);
   156→    }
   157→  }, [initialTab]);
   158→
   159→  // Local state for editing (synced with task prop)
   160→  const [title, setTitle] = useState('');
   161→  const [description, setDescription] = useState('');
   162→  const [startDate, setStartDate] = useState<string | null>(null);
   163→  const [dueDate, setDueDate] = useState<string | null>(null);
   164→  const [priority, setPriority] = useState<TaskPriority>('medium');
   165→  const [tags, setTags] = useState<string[]>([]);
   166→  const [status, setStatus] = useState<TaskStatus>('todo');
   167→  const [newTag, setNewTag] = useState('');
   168→  const [effort, setEffort] = useState<EffortEstimate | undefined>(undefined);
   169→  const [customStatus, setCustomStatus] = useState<CustomStatus | undefined>(undefined);
   170→  const [timeEstimate, setTimeEstimate] = useState<number | undefined>(undefined);
   171→  const [assignees, setAssignees] = useState<string[]>([]);
   172→  const [progress, setProgress] = useState<number>(0); // Phase 1.5: Progress %
   173→
   174→  // P1: Recurring tasks state
   175→  const [showRecurrencePicker, setShowRecurrencePicker] = useState(false);
   176→
   177→  // Phase 1.2: Auto-shift dependent tasks
   178→  const { autoShiftDependentTasks, setAutoShiftDependentTasks } = useSettingsStore();
   179→  const [pendingShifts, setPendingShifts] = useState<Array<{taskId: string; newStartDate: string | null; newDueDate: string | null; reason: string}> | null>(null);
   180→
   181→  // Checklist state
   182→  const [newChecklistItem, setNewChecklistItem] = useState('');
   183→
   184→  // Comment state
   185→  const [newCommentText, setNewCommentText] = useState('');
   186→
   187→  // Subtask state
   188→  const [showAddSubtaskForm, setShowAddSubtaskForm] = useState(false);
   189→  const [newSubtaskTitle, setNewSubtaskTitle] = useState('');
   190→  const [newSubtaskDescription, setNewSubtaskDescription] = useState('');
   191→  const [newSubtaskPriority, setNewSubtaskPriority] = useState<TaskPriority>('medium');
   192→  const [newSubtaskDueDate, setNewSubtaskDueDate] = useState('');
   193→
   194→  // Phase 3.2: Attachment state
   195→  const [previewAttachment, setPreviewAttachment] = useState<TaskAttachment | null>(null);
   196→
   197→  // Phase 2 Quick Wins: Inline date editing
   198→  const [isEditingStartDate, setIsEditingStartDate] = useState(false);
   199→  const [isEditingDueDate, setIsEditingDueDate] = useState(false);
   200→
   201→  // No longer need local state for dependency selection - handled by DependencyPicker
   202→
   203→  // Sync local state with task prop when task changes
   204→  useEffect(() => {
   205→    if (task) {
   206→      setTitle(task.title);
   207→      setDescription(task.description);
   208→      setStartDate(task.startDate);
   209→      setDueDate(task.dueDate);
   210→      setPriority(task.priority);
   211→      setTags(task.tags);
   212→      setStatus(task.status);
   213→      setEffort(task.effort);
   214→      setCustomStatus(task.customStatus);
   215→      setTimeEstimate(task.timeTracking?.estimated);
   216→      setAssignees(task.assignees || []);
   217→      setProgress(task.progress || 0); // Phase 1.5
   218→    }
   219→  }, [task]);
   220→
   221→  // Tab persistence
   222→  useEffect(() => {
   223→    localStorage.setItem('kanban-detail-panel-tab', activeTab);
   224→  }, [activeTab]);
   225→
   226→  // Save and close handler
   227→  const handleSaveAndClose = useCallback(() => {
   228→    if (!task) return;
   229→    onSave(task.id, {
   230→      title,
   231→      description,
   232→      startDate,
   233→      dueDate,
   234→      priority,
   235→      tags,
   236→      status,
   237→      assignees,
   238→    });
   239→    onClose();
   240→  }, [task, onSave, onClose, title, description, startDate, dueDate, priority, tags, status, assignees]);
   241→
   242→  // Keyboard shortcut: Cmd+Enter to save and close
   243→  useEffect(() => {
   244→    const handleKeyDown = (e: KeyboardEvent) => {
   245→      if ((e.metaKey || e.ctrlKey) && e.key === 'Enter' && isOpen) {
   246→        e.preventDefault();
   247→        handleSaveAndClose();
   248→      }
   249→    };
   250→
   251→    if (isOpen) {
   252→      document.addEventListener('keydown', handleKeyDown);
   253→    }
   254→
   255→    return () => {
   256→      document.removeEventListener('keydown', handleKeyDown);
   257→    };
   258→  }, [isOpen, handleSaveAndClose]);
   259→
   260→  if (!task) return null;
   261→
   262→  const handleFieldBlur = (field: keyof Task, value: unknown) => {
   263→    // Phase 1.2: Check if date change triggers dependent shifts
   264→    if ((field === 'startDate' || field === 'dueDate') && task) {
   265→      const oldStartDate = task.startDate;
   266→      const oldDueDate = task.dueDate;
   267→      const newStartDate = field === 'startDate' ? (value as string | null) : task.startDate;
   268→      const newDueDate = field === 'dueDate' ? (value as string | null) : task.dueDate;
   269→
   270→      // Check if auto-shift is enabled and dates actually changed
   271→      if (shouldAutoShift(
   272→        { ...task, startDate: newStartDate, dueDate: newDueDate },
   273→        oldStartDate,
   274→        oldDueDate,
   275→        autoShiftDependentTasks
   276→      )) {
   277→        // Calculate what shifts would be needed
   278→        const shifts = calculateDependentShifts(
   279→          { ...task, startDate: newStartDate, dueDate: newDueDate },
   280→          oldStartDate,
   281→          oldDueDate,
   282→          tasks
   283→        );
   284→
   285→        if (shifts.length > 0) {
   286→          // Show confirmation dialog
   287→          setPendingShifts(shifts);
   288→          // Don't save yet - wait for user confirmation
   289→          return;
   290→        }
   291→      }
   292→    }
   293→
   294→    // Auto-save on blur (normal case or no shifts needed)
   295→    onSave(task.id, { [field]: value });
   296→  };
   297→
   298→  const handleAddTag = () => {
   299→    if (newTag.trim() && !tags.includes(newTag.trim())) {
   300→      const updatedTags = [...tags, newTag.trim()];
   301→      setTags(updatedTags);
   302→      onSave(task.id, { tags: updatedTags });
   303→      setNewTag('');
   304→    }
   305→  };
   306→
   307→  const handleRemoveTag = (tagToRemove: string) => {
   308→    const updatedTags = tags.filter(tag => tag !== tagToRemove);
   309→    setTags(updatedTags);
   310→    onSave(task.id, { tags: updatedTags });
   311→  };
   312→
   313→  // Dependency handlers
   314→  const handleAddDependency = (dependency: TaskDependency) => {
   315→    if (!task) return;
   316→    addDependency(task.id, dependency);
   317→  };
   318→
   319→  const handleRemoveDependency = (dependencyId: string) => {
   320→    if (!task) return;
   321→    removeDependency(task.id, dependencyId);
   322→  };
   323→
   324→  // Get dependency label for display
   325→  const getDependencyLabel = (type: DependencyType): string => {
   326→    const labels = {
   327→      'finish-to-start': 'FS',
   328→      'start-to-start': 'SS',
   329→      'finish-to-finish': 'FF',
   330→      'start-to-finish': 'SF',
   331→    };
   332→    return labels[type];
   333→  };
   334→
   335→  const getDependencyIcon = (type: DependencyType): string => {
   336→    const icons = {
   337→      'finish-to-start': '⏭️',
   338→      'start-to-start': '🤝',
   339→      'finish-to-finish': '🏁',
   340→      'start-to-finish': '🔄',
   341→    };
   342→    return icons[type];
   343→  };
   344→
   345→  // Phase 1.2: Shift confirmation handlers
   346→  const handleConfirmShifts = () => {
   347→    if (!pendingShifts || !task) return;
   348→
   349→    // Apply the date change to the current task first
   350→    const dateField = startDate !== task.startDate ? 'startDate' : 'dueDate';
   351→    const dateValue = startDate !== task.startDate ? startDate : dueDate;
   352→    onSave(task.id, { [dateField]: dateValue });
   353→
   354→    // Then apply all dependent shifts
   355→    applyDependentShifts(pendingShifts);
   356→
   357→    // Close dialog
   358→    setPendingShifts(null);
   359→  };
   360→
   361→  const handleCancelShifts = () => {
   362→    if (!task) return;
   363→
   364→    // Revert local state to original values
   365→    setStartDate(task.startDate);
   366→    setDueDate(task.dueDate);
   367→
   368→    // Close dialog
   369→    setPendingShifts(null);
   370→  };
   371→
   372→  const handleDontAskAgain = () => {
   373→    // Disable auto-shift
   374→    setAutoShiftDependentTasks(false);
   375→
   376→    // Close dialog without applying shifts
   377→    handleCancelShifts();
   378→  };
   379→
   380→  // P2: Save task as template
   381→  const handleSaveAsTemplate = () => {
   382→    if (!task) return;
   383→
   384→    // Check if task has content worth templating
   385→    const hasContent = Boolean(
   386→      task.description ||
   387→      (task.checklist && task.checklist.length > 0) ||
   388→      (task.customFields && Object.keys(task.customFields).length > 0)
   389→    );
   390→
   391→    if (!hasContent) {
   392→      alert('Task must have description, checklist, or custom fields to save as template');
   393→      return;
   394→    }
   395→
   396→    // Create template from current task
   397→    const template = createTemplate(task);
   398→
   399→    // Show success feedback
   400→    alert(`Template "${template.name}" created successfully!`);
   401→  };
   402→
   403→  const availableTasks = tasks.filter(t => t.id !== task?.id);
   404→
   405→  return (
   406→    <>
   407→    <Modal isOpen={isOpen} onClose={onClose} title={task.title} maxWidth="2xl">
   408→      <div className="flex flex-col md:flex-row gap-3 pr-1">
   409→        {/* Left Side: Task Metadata (60%) */}
   410→        <div className="w-full md:w-3/5 space-y-2">
   411→          {/* Title */}
   412→          <div>
   413→            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
   414→              Title
   415→            </label>
   416→            <input
   417→              type="text"
   418→              value={title}
   419→              onChange={(e) => setTitle(e.target.value)}
   420→              onBlur={() => handleFieldBlur('title', title)}
   421→              className="w-full text-base font-semibold bg-transparent border-none outline-none text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue rounded px-1 py-0.5"
   422→              autoFocus
   423→            />
   424→          </div>
   425→
   426→          {/* Description */}
   427→          <div>
   428→            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
   429→              Description
   430→            </label>
   431→            <textarea
   432→              value={description}
   433→              onChange={(e) => setDescription(e.target.value)}
   434→              onBlur={() => handleFieldBlur('description', description)}
   435→              placeholder="Add a description..."
   436→              className="w-full min-h-[48px] p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-xs text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue outline-none resize-y"
   437→              rows={2}
   438→            />
   439→          </div>
   440→
   441→          {/* Dates (Inline NL Editing) */}
   442→          <div className={`grid ${task?.isMilestone ? 'grid-cols-1' : 'grid-cols-2'} gap-4`}>
   443→            {/* Phase 1.6: Hide start date for milestones (single-point events) */}
   444→            {!task?.isMilestone && (
   445→              <div>
   446→                <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
   447→                  Start Date
   448→                </label>
   449→                {isEditingStartDate ? (
   450→                  <NaturalLanguageDateInput
   451→                    value={startDate}
   452→                    onChange={(date) => {
   453→                      setStartDate(date);
   454→                      handleFieldBlur('startDate', date);
   455→                      setIsEditingStartDate(false);
   456→                    }}
   457→                    label=""
   458→                    autoFocus
   459→                    placeholder="Type 'tomorrow', 'next Monday'..."
   460→                  />
   461→                ) : (
   462→                  <button
   463→                    onClick={() => setIsEditingStartDate(true)}
   464→                    className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-left hover:bg-surface-light-elevated dark:hover:bg-neutral-800 transition-colors group flex items-center justify-between"
   465→                  >
   466→                    {startDate ? (
   467→                      <>
   468→                        <span className="text-text-light-primary dark:text-text-dark-primary">
   469→                          {formatDateForDisplay(new Date(startDate))}
   470→                        </span>
   471→                        <button
   472→                          onClick={(e) => {
   473→                            e.stopPropagation();
   474→                            setStartDate(null);
   475→                            handleFieldBlur('startDate', null);
   476→                          }}
   477→                          className="opacity-0 group-hover:opacity-100 text-text-light-secondary dark:text-text-dark-secondary hover:text-red-600 transition-opacity"
   478→                          aria-label="Clear start date"
   479→                        >
   480→                          ✕
   481→                        </button>
   482→                      </>
   483→                    ) : (
   484→                      <span className="text-text-light-secondary dark:text-text-dark-secondary">+ Add start date</span>
   485→                    )}
   486→                  </button>
   487→                )}
   488→              </div>
   489→            )}
   490→            <div>
   491→              <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
   492→                {task?.isMilestone ? 'Milestone Date' : 'Due Date'}
   493→              </label>
   494→              {isEditingDueDate ? (
   495→                <NaturalLanguageDateInput
   496→                  value={dueDate}
   497→                  onChange={(date) => {
   498→                    setDueDate(date);
   499→                    handleFieldBlur('dueDate', date);
   500→                    setIsEditingDueDate(false);
   501→                  }}
   502→                  label=""
   503→                  autoFocus
   504→                  placeholder="Type 'tomorrow', 'next Friday'..."
   505→                />
   506→              ) : (
   507→                <button
   508→                  onClick={() => setIsEditingDueDate(true)}
   509→                  className={`w-full p-2 bg-surface-light dark:bg-surface-dark border rounded-lg text-sm text-left hover:bg-surface-light-elevated dark:hover:bg-neutral-800 transition-colors group flex items-center justify-between ${
   510→                    dueDate && new Date(dueDate) < new Date() && task?.status !== 'done'
   511→                      ? 'border-red-500 bg-red-50 dark:bg-red-950/20'
   512→                      : 'border-border-light dark:border-border-dark'
   513→                  }`}
   514→                >
   515→                  {dueDate ? (
   516→                    <>
   517→                      <div className="flex-1">
   518→                        <span className={`${
   519→                          dueDate && new Date(dueDate) < new Date() && task?.status !== 'done'
   520→                            ? 'text-red-600 dark:text-red-400 font-medium'
   521→                            : 'text-text-light-primary dark:text-text-dark-primary'
   522→                        }`}>
   523→                          {formatDateForDisplay(new Date(dueDate))}
   524→                        </span>
   525→                        {dueDate && (() => {
   526→                          const days = differenceInDays(new Date(dueDate), new Date());
   527→                          const isOverdue = days < 0 && task?.status !== 'done';
   528→                          const isDueToday = days === 0;
   529→
   530→                          if (isOverdue) {
   531→                            return (
   532→                              <span className="ml-2 text-xs text-red-600 dark:text-red-400">
   533→                                overdue by {Math.abs(days)} day{Math.abs(days) !== 1 ? 's' : ''}
   534→                              </span>
   535→                            );
   536→                          }
   537→                          if (isDueToday) {
   538→                            return <span className="ml-2 text-xs text-orange-600 dark:text-orange-400">due today</span>;
   539→                          }
   540→                          if (days > 0 && days <= 7) {
   541→                            return <span className="ml-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">{days} day{days !== 1 ? 's' : ''} from now</span>;
   542→                          }
   543→                          return null;
   544→                        })()}
   545→                      </div>
   546→                      <button
   547→                        onClick={(e) => {
   548→                          e.stopPropagation();
   549→                          setDueDate(null);
   550→                          handleFieldBlur('dueDate', null);
   551→                        }}
   552→                        className="opacity-0 group-hover:opacity-100 text-text-light-secondary dark:text-text-dark-secondary hover:text-red-600 transition-opacity"
   553→                        aria-label="Clear due date"
   554→                      >
   555→                        ✕
   556→                      </button>
   557→                    </>
   558→                  ) : (
   559→                    <span className="text-text-light-secondary dark:text-text-dark-secondary">+ Add due date</span>
   560→                  )}
   561→                </button>
   562→              )}
   563→            </div>
   564→          </div>
   565→
   566→          {/* Priority */}
